mapper.update:
		update cotdl.tbl_piiconfkeymap
		set 
			key_cols= #{key_cols, jdbcType=VARCHAR},
			src_owner= #{src_owner, jdbcType=VARCHAR},
			src_table_name= #{src_table_name, jdbcType=VARCHAR},
			where_col= #{where_col, jdbcType=VARCHAR},
			where_key_name= #{where_key_name, jdbcType=VARCHAR},
			parallelcnt= #{parallelcnt, jdbcType=VARCHAR},
			status= #{status, jdbcType=VARCHAR},
			sqltype= #{sqltype, jdbcType=VARCHAR},
			insertstr= #{insertstr, jdbcType=VARCHAR},
			wherestr= #{wherestr, jdbcType=VARCHAR},
			refstr= #{refstr, jdbcType=VARCHAR},
			regdate= to_date(#{regdate, jdbcType=VARCHAR},'yyyy/mm/dd'),
			upddate= SYSDATE,
			reguserid= #{reguserid, jdbcType=VARCHAR},
			upduserid= #{upduserid, jdbcType=VARCHAR}
		where keymap_id= #{keymap_id, jdbcType=VARCHAR}
			and key_name= #{key_name, jdbcType=VARCHAR}
			and	db= #{db, jdbcType=VARCHAR}
			and	seq1= #{seq1}
			and	seq2= #{seq2}
			and	seq3= #{seq3}

mapper.select:
 
		 
		select 
			keymap_id, key_name, db, seq1, seq2, seq3, key_cols, src_owner, src_table_name, where_col, where_key_name, parallelcnt, status, sqltype, insertstr, wherestr, refstr, regdate, upddate, reguserid, upduserid
		from ( 
				select
					 ROWNUM rn, keymap_id, key_name, db, seq1, seq2, seq3, key_cols, src_owner, src_table_name, where_col, where_key_name, parallelcnt, status, sqltype, insertstr, wherestr, refstr, regdate, upddate, reguserid, upduserid 
				from (
						select keymap_id, key_name, db, seq1, seq2, seq3, key_cols, src_owner, src_table_name, where_col, where_key_name, parallelcnt, status, sqltype, insertstr, wherestr, refstr, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduserid
						  from cotdl.tbl_piiconfkeymap order by seq1, seq2, seq3 
					 ) f
				where 
		
	    
		
						
							and keymap_id like '%'||#{search1}||'%'
						
						
							and key_name like '%'||#{search2}||'%'
						
						
							and key_cols like '%'||#{search3}||'%'
						
		
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by keymap_id, seq1, seq2, seq3
			  ) r
		where rn > (#{pagenum} -1) * #{amount} 
		order by keymap_id, seq1, seq2, seq3
